import{bQ as d,aL as a,u as r,G as e}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"高可用架构","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/09-高可用架构.md","filePath":"00.互联网与架构基础/09-高可用架构.md","lastUpdated":null}'),h={name:"00.互联网与架构基础/09-高可用架构.md"};function o(i,t,l,p,n,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="高可用架构" tabindex="-1">高可用架构 <a class="header-anchor" href="#高可用架构" aria-label="Permalink to &quot;高可用架构&quot;">​</a></h1><p>机器会坏，进程会崩，磁盘会满，网络会抖，数据库也可能突然不可写。高可用关注的就是这些事发生以后，服务还能不能继续对外工作。</p><p>单机系统最明显的问题是单点故障。只有一台机器时，它坏了，入口、应用和数据都跟着不可用。高可用从减少这些“只有一个”的关键点开始。</p><h2 id="一、单点" tabindex="-1">一、单点 <a class="header-anchor" href="#一、单点" aria-label="Permalink to &quot;一、单点&quot;">​</a></h2><p>系统里任何关键对象只剩一个，都可能变成单点。</p><table tabindex="0"><thead><tr><th>单点</th><th>故障影响</th></tr></thead><tbody><tr><td>单台 Web 服务器</td><td>页面和接口全部不可访问</td></tr><tr><td>单个负载均衡</td><td>后端都正常，入口仍然不可用</td></tr><tr><td>单个数据库主库</td><td>写入失败，部分接口不可用</td></tr><tr><td>单个 Redis</td><td>缓存、会话、分布式锁异常</td></tr><tr><td>单条公网线路</td><td>外部访问中断</td></tr></tbody></table><p>减少单点的基本办法是准备多个实例，并让流量或角色可以切过去。多个实例之间还要有健康检查、故障判断和切换机制。</p><h2 id="二、主备" tabindex="-1">二、主备 <a class="header-anchor" href="#二、主备" aria-label="Permalink to &quot;二、主备&quot;">​</a></h2><p>主备很好理解：一台主节点工作，一台备节点等着接管。主节点故障后，备节点变成新的主节点。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User%5B%22%E7%94%A8%E6%88%B7%22%5D%0A%20%20VIP%5B%22VIP%20%2F%20%E5%85%A5%E5%8F%A3%E5%9C%B0%E5%9D%80%22%5D%0A%20%20Primary%5B%22%E4%B8%BB%E8%8A%82%E7%82%B9%22%5D%0A%20%20Standby%5B%22%E5%A4%87%E8%8A%82%E7%82%B9%22%5D%0A%20%20Data%5B%22%E6%95%B0%E6%8D%AE%E5%90%8C%E6%AD%A5%22%5D%0A%0A%20%20User%20--%3E%20VIP%0A%20%20VIP%20--%3E%20Primary%0A%20%20Primary%20--%3E%20Data%0A%20%20Data%20--%3E%20Standby%0A"></div><p>数据库、负载均衡、网关这类组件经常有主备形态。备节点平时可能不接流量，也可能只接读请求。</p><p>主备最关键的是切换。切得慢，业务中断时间长；判断错了，可能两个节点都认为自己是主，这叫脑裂。脑裂会让两边同时写数据，后面很难处理。</p><h2 id="三、故障怎么切" tabindex="-1">三、故障怎么切 <a class="header-anchor" href="#三、故障怎么切" aria-label="Permalink to &quot;三、故障怎么切&quot;">​</a></h2><p>故障转移要先发现故障，再把入口或主角色切到健康节点。</p><p>常见机制：</p><table tabindex="0"><thead><tr><th>机制</th><th>作用</th></tr></thead><tbody><tr><td>心跳</td><td>节点之间定期确认对方是否还活着</td></tr><tr><td>健康检查</td><td>入口层探测后端是否可用</td></tr><tr><td>VIP 漂移</td><td>虚拟 IP 从故障节点漂到健康节点</td></tr><tr><td>Leader 选举</td><td>多个节点选出一个主节点</td></tr><tr><td>仲裁</td><td>防止网络分区时出现多个主节点</td></tr></tbody></table><p>Keepalived 常用于 VIP 漂移。数据库集群会有自己的主备选举或故障转移机制。Kubernetes 控制器也会持续观察状态，把不符合期望的对象拉回去。</p><p>用户侧可能看到一小段时间的连接失败、502、只读提示或登录状态丢失。切换后除了看入口能访问，还要确认写入是否恢复、旧主是否还在接写请求、监控里错误率是否回落。</p><h2 id="四、集群不都一样" tabindex="-1">四、集群不都一样 <a class="header-anchor" href="#四、集群不都一样" aria-label="Permalink to &quot;四、集群不都一样&quot;">​</a></h2><p>集群就是多个节点共同提供能力，但不同组件的“集群”含义不一样。</p><table tabindex="0"><thead><tr><th>类型</th><th>常见特点</th></tr></thead><tbody><tr><td>Web 集群</td><td>多个无状态实例，入口负载均衡分发</td></tr><tr><td>Redis Cluster</td><td>数据按 slot 分布到不同节点</td></tr><tr><td>Kafka 集群</td><td>topic 分区分布到多个 broker</td></tr><tr><td>数据库集群</td><td>主从、组复制、分片或多主</td></tr><tr><td>Kubernetes 集群</td><td>多个节点承载 Pod，控制面调度和管理</td></tr></tbody></table><p>无状态服务做集群相对简单，请求打到任意实例都能处理。带状态服务更复杂，因为要说清数据在哪、谁能写、故障时数据是否完整。</p><h2 id="五、数据一致" tabindex="-1">五、数据一致 <a class="header-anchor" href="#五、数据一致" aria-label="Permalink to &quot;五、数据一致&quot;">​</a></h2><p>高可用最难的部分往往是数据。应用多实例可以靠负载均衡解决，数据库多副本却要处理复制延迟、主从切换、写入冲突和数据恢复。</p><p>常见矛盾：</p><table tabindex="0"><thead><tr><th>场景</th><th>风险</th></tr></thead><tbody><tr><td>主从复制延迟</td><td>刚写入的数据，从库查不到</td></tr><tr><td>主库故障切换</td><td>最新少量事务可能还没同步到新主</td></tr><tr><td>多主写入</td><td>两边同时修改同一行，可能冲突</td></tr><tr><td>网络分区</td><td>节点互相看不到，容易误判对方故障</td></tr></tbody></table><p>很多系统选择“一个主库负责写，多副本负责读和容灾”，就是为了减少写冲突。写入口越多，数据一致越难。</p><h2 id="六、可用性也有成本" tabindex="-1">六、可用性也有成本 <a class="header-anchor" href="#六、可用性也有成本" aria-label="Permalink to &quot;六、可用性也有成本&quot;">​</a></h2><p>高可用会带来更多部署、监控、切换演练和排错成本。所有组件都堆成双份，系统不一定更清楚，也不一定更可靠。</p><p>内部低频工具可能只需要定期备份和快速重建。核心交易系统则需要主备、跨机房、限流、降级、灰度发布和持续演练。</p><p>高可用最终要回答几个问题：单点在哪里，故障怎么发现，流量怎么切走，数据是否完整，切换后怎么确认业务真的恢复。</p>',31)])])}const _=d(h,[["render",o]]);export{c as __pageData,_ as default};
